class PaymentModule {
  final String apiUrl = 'https://your.api.endpoint/payment';

  Future<void> initialize() async {
    await InAppPurchase.instance.isAvailable();
  }

  Future<List<ProductDetails>> fetchProducts(List<String> productIds) async {
    Set<String> ids = Set.from(productIds);
    ProductDetailsResponse response = await InAppPurchase.instance.queryProductDetails(ids);
    if (response.notFoundIDs.isNotEmpty) {
      throw Exception('Product not found');
    }
    return response.productDetails;
  }

  Future<void> purchaseProduct(ProductDetails product) async {
    final PurchaseParam purchaseParam = PurchaseParam(productDetails: product);
    await InAppPurchase.instance.buyConsumable(purchaseParam: purchaseParam);
  }

  Future<void> processPayment(String paymentMethodId, double amount) async {
    final response = await http.post(Uri.parse(apiUrl),
      body: {
        'paymentMethodId': paymentMethodId,
        'amount': amount.toString(),
      },
    );
    if (response.statusCode != 200) {
      throw Exception('Payment processing failed');
    }
  }

  Future<void> completePurchase(PurchaseDetails purchaseDetails) async {
    if (purchaseDetails.status == PurchaseStatus.purchased) {
      // Validate receipt with your server
      await processPayment(purchaseDetails.purchaseID, purchaseDetails.productID);
    }
  }
}

